@spec mm_multi_note_delete_spec  src=tests/specs/mm_multi_note_delete_spec.lua  loc=56  sha=37ed80d  cases=1
@exercises midiManager (h.mm)
@surface   mm:modify, mm:notes, mm:delete
@harness   fakeReaper:bindTake

# Intent
  Multi-deleteNote in one mm:modify must resolve REAPER note idxs against
  the live array, not against idxs captured before the deletes started
  shifting things. MIDI_DeleteNote shifts all higher idxs down by one;
  a subsequent delete using a stale captured idx hits the wrong note.
  
  Reproduces the symptom the user hit: notes ABAB in one column, select
  first AB, delete → .B.B (A1 deleted as expected, but the second delete
  hit A2 instead of B1, leaving B1 and B2 surviving).

# Helpers
  @fn freshTake()  @ 13-19

# Cases
  @case 'multi-deleteNote in one modify deletes exactly the uuids passed'  [pure]  @ 23-54

# Uses (outbound edges)
  @use call mm:modify  @ 29,40
  @use call mm:notes  @ 37,46
  @use call mm:delete  @ 41,42

# Fields (r read / w write incl. constructor keys)
  @field w chan  @ 30,31,32,33
  @field w endppq  @ 30,31,32,33
  @field w evType  @ 30,31,32,33
  @field w name  @ 23
  @field r pitch  @ 46,51,53
  @field w pitch  @ 30,31,32,33,46
  @field r ppq  @ 37,46,49,50,52
  @field w ppq  @ 30,31,32,33,46
  @field w reaper  @ 15
  @field w run  @ 24
  @field r uuid  @ 37
  @field w vel  @ 30,31,32,33
